/**
 * End-to-end test that exercises strip-unminified-prod against output
 * generated by an actual `wp-build` invocation. The fixture is built fresh
 * by the `before` hook, so any drift in `@wordpress/build`'s PHP templates
 * (new ternary shape, renamed loader, etc.) fails this test immediately —
 * one PR earlier than a consumer's `build-production` would.
 *
 * The fixture under `tests/fixtures/wp-build-source/` is a minimal
 * wp-build-compatible package exercising the strip script's four targets:
 * one route with `stage` + `route` entries emits paired `.js`/`.min.js`
 * under `build/routes/dashboard/`, one `wpScript` sub-package with a
 * `build-style/style.css` emits paired `.css`/`.min.css` under
 * `build/styles/css-test/` plus paired `.js`/`.min.js` under
 * `build/scripts/css-test/`, and one widget under `build/widgets/hello-world`.
 *
 * The fixture is *not* a workspace member and ships nothing — `tests/**`
 * is production-exclude in this package's .gitattributes, and the
 * generated build dir is gitignored.
 */

const { spawnSync } = require( 'child_process' );
const { existsSync, readFileSync, rmSync } = require( 'fs' );
const assert = require( 'node:assert/strict' );
const { describe, it, before, after } = require( 'node:test' );
const path = require( 'path' );
const {
	strip,
	hasUnpatchedFallback,
	PHP_TARGETS,
} = require( '../../bin/strip-unminified-prod-lib.js' );

const POLYFILLS_DIR = path.join( __dirname, '..', '..' );
const FIXTURE_DIR = path.join( POLYFILLS_DIR, 'tests', 'fixtures', 'wp-build-source' );
const FIXTURE_BUILD = path.join( FIXTURE_DIR, 'build' );
const WP_BUILD_BIN = path.join( POLYFILLS_DIR, 'node_modules', '.bin', 'wp-build' );

// Skip cleanly if wp-build isn't installed (e.g. someone checked out the
// repo without running `pnpm install`).
const wpBuildAvailable = existsSync( WP_BUILD_BIN );

const PAIRED_BUNDLES = [
	[ 'routes/dashboard/content.js', 'routes/dashboard/content.min.js' ],
	[ 'routes/dashboard/route.js', 'routes/dashboard/route.min.js' ],
	[ 'scripts/css-test/index.js', 'scripts/css-test/index.min.js' ],
	[ 'styles/css-test/style.css', 'styles/css-test/style.min.css' ],
	[ 'widgets/hello-world/render.js', 'widgets/hello-world/render.min.js' ],
	[ 'widgets/hello-world/widget.js', 'widgets/hello-world/widget.min.js' ],
];

describe(
	'strip-unminified-prod against real wp-build output',
	{ skip: ! wpBuildAvailable },
	() => {
		before( () => {
			rmSync( FIXTURE_BUILD, { recursive: true, force: true } );
			const result = spawnSync( WP_BUILD_BIN, [], {
				cwd: FIXTURE_DIR,
				encoding: 'utf8',
			} );
			if ( result.status !== 0 ) {
				throw new Error(
					`wp-build failed (exit ${ result.status }):\n` +
						`stdout: ${ result.stdout }\nstderr: ${ result.stderr }`
				);
			}
		} );

		after( () => {
			// Top-level wp-build output…
			rmSync( FIXTURE_BUILD, { recursive: true, force: true } );
			// …and the per-package transpilation output wp-build writes
			// under packages/*/build/ during Phase 1.
			rmSync( path.join( FIXTURE_DIR, 'packages', 'css-test', 'build' ), {
				recursive: true,
				force: true,
			} );
		} );

		it( 'emits all four PHP loaders that the strip script targets', () => {
			for ( const name of PHP_TARGETS ) {
				assert.ok(
					existsSync( path.join( FIXTURE_BUILD, name ) ),
					`${ name } should exist after wp-build`
				);
			}
		} );

		it( 'emits paired unminified + minified bundles in every wp-build subdir', () => {
			// Pre-strip: every pair we care about should exist. If wp-build
			// stops emitting one half, the assertion below tells us which.
			for ( const [ unminified, minified ] of PAIRED_BUNDLES ) {
				assert.ok(
					existsSync( path.join( FIXTURE_BUILD, unminified ) ),
					`${ unminified } should exist before stripping`
				);
				assert.ok(
					existsSync( path.join( FIXTURE_BUILD, minified ) ),
					`${ minified } should exist before stripping`
				);
			}
		} );

		it( 'emits the SCRIPT_DEBUG ternaries in shapes the strip patches recognise', () => {
			// Pre-strip sanity check: the real output should match at least one
			// of our known patterns. If `hasUnpatchedFallback` returns false
			// for any of the four loaders, the template has drifted to a
			// shape neither our REPLACEMENTS nor our safety net can detect.
			for ( const name of PHP_TARGETS ) {
				const src = readFileSync( path.join( FIXTURE_BUILD, name ), 'utf8' );
				assert.ok(
					hasUnpatchedFallback( src ),
					`${ name } should contain a SCRIPT_DEBUG-driven fallback before stripping`
				);
			}
		} );

		it( 'strips paired unminified bundles and patches every PHP loader', () => {
			const result = strip( FIXTURE_BUILD );
			assert.equal( result.skipped, false );
			// 2 routes paired + 1 wpScript paired + 1 CSS paired + 1 widget (2 paired) = 6 deletions.
			assert.equal( result.deletedFiles, 6 );
			assert.equal( result.patchedFiles, 5 );

			// Paired bundles gone, minified siblings retained.
			for ( const [ unminified, minified ] of PAIRED_BUNDLES ) {
				assert.equal(
					existsSync( path.join( FIXTURE_BUILD, unminified ) ),
					false,
					`${ unminified } should be removed`
				);
				assert.equal(
					existsSync( path.join( FIXTURE_BUILD, minified ) ),
					true,
					`${ minified } should be retained`
				);
			}

			// Paired `.js.map` sourcemaps for the deleted `.js` files are
			// also dropped — they're not useful without the unminified bundle.
			assert.equal(
				existsSync( path.join( FIXTURE_BUILD, 'scripts/css-test/index.js.map' ) ),
				false
			);

			// No SCRIPT_DEBUG fallback remains in any loader.
			for ( const name of PHP_TARGETS ) {
				const src = readFileSync( path.join( FIXTURE_BUILD, name ), 'utf8' );
				assert.equal(
					hasUnpatchedFallback( src ),
					false,
					`${ name } still has a SCRIPT_DEBUG fallback after stripping`
				);
			}
		} );

		it( 'is idempotent on real output — a second pass changes nothing', () => {
			const result = strip( FIXTURE_BUILD );
			assert.deepEqual( result, { deletedFiles: 0, patchedFiles: 0, skipped: false } );
		} );
	}
);
